```kotlin
// 서버 측 응답 빌드
val response = ListCallsResponse.newBuilder()
    .addAllCalls(calls.map { it.toProto() })   // List 일괄 추가
    .addCalls(singleCall.toProto())             // 단건 추가
    .setTotal(total)
    .build()

// 클라이언트 측 수신
val callList: List<CallRecord> = response.callsList  // Kotlin List로 자동 변환
