## 4. 기존 서비스에 필드 추가 시 Backward Compatibility 유지 방법

grpc-skill SKILL.md 주의사항 기준 (`Proto 변경 시 하위 호환성 유지 (필드 번호 재사용 금지)`)을 확장하면 다음과 같습니다.

### 안전한 변경 (하위 호환 유지됨)

```protobuf
// 변경 전
message Feature {
  string id         = 1;
  string name       = 2;
  string user_id    = 3;
  string created_at = 4;
}

// 변경 후 - 안전: 새 번호로 필드 추가
message Feature {
  string id           = 1;
  string name         = 2;
  string user_id      = 3;
  string created_at   = 4;
  string description  = 5;  // 신규 추가 - 구 클라이언트는 무시
  optional int32 view_count = 6;  // optional로 명시적 선택 필드 표현
}
```

### 위험한 변경 (하위 호환 깨짐)

```protobuf
// [금지] 필드 번호 변경
message Feature {
  string id         = 1;
  string name       = 10;  // 2 -> 10 변경 금지
}

// [금지] 필드 타입 변경 (일부 예외 제외)
message Feature {
  int64 id = 1;  // string -> int64 타입 변경 금지
}

// [금지] 번호 재사용
message Feature {
  string id         = 1;
  // name 삭제 후
  string title      = 2;  // 2번 재사용 금지
}
```

### 필드 삭제 시 안전한 처리 절차

```protobuf
// Step 1: 삭제 전 deprecated 주석 추가하여 배포
message Feature {
  string id         = 1;
  string name       = 2;
  string user_id    = 3;
  string created_at = 4;
  // deprecated: old_score 는 manner_score로 대체됨
  float  old_score  = 5;
  float  manner_score = 6;  // 신규 대체 필드
}

// Step 2: 클라이언트 마이그레이션 완료 후 reserved로 잠금
message Feature {
  string id           = 1;
  string name         = 2;
  string user_id      = 3;
  string created_at   = 4;
  reserved 5;               // old_score 번호 영구 잠금
  reserved "old_score";     // 필드명도 잠금
  float  manner_score = 6;
}
```

