## 5. 실제 예시 코드 (Maum 프로젝트 패턴)

### Proto 정의

파일: `protobuf/src/main/proto/call/call_service.proto`

```protobuf
syntax = "proto3";
package call;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.call";

service CallService {
  rpc GetCall(GetCallRequest) returns (GetCallResponse);
  rpc ListCalls(ListCallsRequest) returns (ListCallsResponse);
  rpc StartCall(StartCallRequest) returns (StartCallResponse);
}

enum CallStatus {
  CALL_STATUS_UNKNOWN  = 0;
  CALL_STATUS_WAITING  = 1;
  CALL_STATUS_ACTIVE   = 2;
  CALL_STATUS_ENDED    = 3;
}

message CallRecord {
  string     call_id      = 1;
  string     caller_id    = 2;
  string     receiver_id  = 3;
  CallStatus status       = 4;
  int64      started_at   = 5;
  int32      duration_sec = 6;
  // 신규 필드 추가 (7번부터 이어서)
  optional string  topic      = 7;   // 통화 주제 (선택)
  optional float   quality    = 8;   // 통화 품질 점수
  repeated string  tag_list   = 9;   // 태그 목록

  reserved 10, 11;                   // 향후 예약 삭제 필드용 공간
}

message GetCallRequest {
  string user_id = 1;
  string call_id = 2;
}

message GetCallResponse {
  CallRecord call = 1;
}

message ListCallsRequest {
  string user_id = 1;
  int32  limit   = 2;
  int32  offset  = 3;
  oneof status_filter {
    CallStatus status    = 4;  // 특정 상태 필터
    bool       all_calls = 5;  // 전체 조회
  }
}

message ListCallsResponse {
  repeated CallRecord calls = 1;
  int32               total = 2;
}
```

### gRPC Service 서버 구현

파일: `{module}/src/main/kotlin/com/maum/backend/controller/call/CallGrpcService.kt`

```kotlin
@GrpcService
class CallGrpcService(
    private val callService: CallService,
) : CallServiceGrpc.CallServiceImplBase() {

    override fun getCall(
        request: GetCallRequest,
        responseObserver: StreamObserver<GetCallResponse>,
    ) {
        val call = callService.getCall(request.userId, request.callId)
        val response = GetCallResponse.newBuilder()
            .setCall(call.toProto())
            .build()
        responseObserver.onNext(response)
        responseObserver.onCompleted()
    }

    override fun listCalls(
        request: ListCallsRequest,
        responseObserver: StreamObserver<ListCallsResponse>,
    ) {
        // oneof 분기 처리
        val statusFilter = when (request.statusFilterCase) {
            ListCallsRequest.StatusFilterCase.STATUS -> request.status
            else -> null
        }

        val (calls, total) = callService.listCalls(
            userId = request.userId,
            limit = request.limit,
            offset = request.offset,
            status = statusFilter,
        )

        val response = ListCallsResponse.newBuilder()
            .addAllCalls(calls.map { it.toProto() })
            .setTotal(total)
            .build()
        responseObserver.onNext(response)
        responseObserver.onCompleted()
    }
}

// Entity -> Proto 변환 확장함수
fun CallEntity.toProto(): CallRecord = CallRecord.newBuilder()
    .setCallId(this.id)
    .setCallerId(this.callerId)
    .setReceiverId(this.receiverId)
    .setStatus(CallStatus.valueOf("CALL_STATUS_${this.status.name}"))
    .setStartedAt(this.startedAt.toEpochMilli())
    .setDurationSec(this.durationSec)
    .apply { this@toProto.topic?.let { setTopic(it) } }     // optional 필드
    .apply { this@toProto.quality?.let { setQuality(it) } } // optional 필드
    .addAllTagList(this.tags)                                // repeated 필드
    .build()
```

### gRPC Client 구현 (GraphQL 모듈)

파일: `graphql/src/main/kotlin/com/maum/backend/service/call/CallGrpcService.kt`

```kotlin
@Service
class CallGrpcService {
    @GrpcClient("call-grpc")
    private lateinit var stub: CallServiceGrpc.CallServiceBlockingStub

    fun getCall(userId: String, callId: String): GetCallResponse {
        val request = GetCallRequest.newBuilder()
            .setUserId(userId)
            .setCallId(callId)
            .build()
        return try {
            stub.getCall(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun listCalls(userId: String, limit: Int, offset: Int): ListCallsResponse {
        val request = ListCallsRequest.newBuilder()
            .setUserId(userId)
            .setLimit(limit)
            .setOffset(offset)
            .setAllCalls(true)  // oneof 설정
            .build()
        return try {
            stub.listCalls(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }
}
```

